const input = $input.first().json;

const message = String(
  input.message ||
  input.user_message ||
  input.chatInput ||
  ''
);

const q = message
  .toLowerCase()
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '');

let output = '';

if (/(horaire|horaires|ouverture|ouvre|ferme)/.test(q)) {
  output = `
Les horaires d'ouverture de l'UPF sont :

- Lundi à vendredi : 8h00 - 17h00
- Samedi : 9h00 - 13h00
- Dimanche : fermé

Source : faq-upf.md.
`.trim();
} else if (/(inscription|documents|administrative|dossier)/.test(q)) {
  output = `
Pour l'inscription, les documents requis sont :

- CIN
- Baccalauréat
- Photos
- Fiche de renseignement

La date limite pour L1 est le 15 septembre 2026.

Source : faq-upf.md.
`.trim();
} else if (/(contact|scolarite|direction|email)/.test(q)) {
  output = `
Contacts utiles :

- Scolarité : scolarite@upf.ma
- Direction : direction@upf.ma
- Filière Informatique : info@upf.ma

Source : faq-upf.md.
`.trim();
} else if (/(examen|examens|notes|rattrapage)/.test(q)) {
  output = `
Informations sur les examens :

- Session normale : janvier pour S1 et juin pour S2
- Session de rattrapage : juillet
- Accès aux notes : portail.upf.ma

Source : faq-upf.md.
`.trim();
} else {
  output = `
Cette information ne figure pas dans les documents disponibles. Contactez scolarite@upf.ma.

Source : faq-upf.md.
`.trim();
}

return [{ json: { output, message } }];
